WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/14.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/14.0/apex.js")}

var valid = true; 
var message = 'The following fields must be filled out before the record can be sealed: \n\n'; 

if ( {!ISBLANK(   HOMEtracker__Service_File__c.HOMEtracker__Income_Certification_Date__c   )} ) { 
valid = false; 
message += '* Income Certification Date (Click Certify Income button)\n'; 
} 

if ( {!ISBLANK(   HOMEtracker__Service_File__c.HOMEtracker__Purchase_Certification_Date__c   )} ) { 
valid = false; 
message += '* Purchase Certification Date (Click Certify Purchase button)\n'; 
} 

if ( {!ISBLANK(  HOMEtracker__Service_File__c.HOMEtracker__Resale_Close_Date__c  )} ) { 
valid = false; 
message += '* Resale Close Date\n'; 
} 

if ( {!ISBLANK(   HOMEtracker__Service_File__c.HOMEtracker__Contract_Sale_Price__c   )} ) { 
valid = false; 
message += '* Contract Sales Price\n'; 
} 

if ( {!ISPICKVAL(  HOMEtracker__Service_File__c.HOMEtracker__Resale_Type__c, '' )} ) { 
valid = false; 
message += '* Resale Type\n'; 
}

var confirmationMessage = "You should Seal a Homeownership File ONLY if a completed resale has taken place, you have entered all of the data, and you are ready to make all the fields read-only. The purpose of sealing a file is to make all the fields on the Service File read-only so that they cannot be easily changed. Note that you can still change related records.\n\nSealing a Service File updates the following:\n- The File Sealed Date is set to today's date.\n- The Service File Record Type will be changed to Sealed Homeownership, which will make the fields read-only.\n- If any address on the applicant or co-applicant's Contact record matches the Property address, those address fields will be cleared on the Contact record.\n\nBefore proceeding, remember to: \n* Click the Copy Addresses to Contacts link to copy the resale address from the Service File to the Contact record(s). \n* Click on the Update Status button to simultaneously update the Property, Applicant Contact and Service File status. \n* If this is a resale, click the Sync Buyer/Seller Data button to update the Statuses and sync transaction information.\n\nAre you ready to continue?";

if (valid) {
confirmed = window.confirm(confirmationMessage);

if (confirmed) {
// run the webservice
var serviceFileID = sforce.apex.execute("HOMEtracker.ServiceFileWebServices","sealServiceFile", {serviceFileID: "{!CASESAFEID(HOMEtracker__Service_File__c.Id)}"});

// redirect to the new task
top.location.replace("/" + serviceFileID);
} 

} else {
alert (message);
}
